## Code Example

```javascript
import { Chain, Tool, Planner } from 'langchain';
import { AgentExecutor } from 'langchain/agents';
import Redis from 'ioredis';

const redis = new Redis(process.env.REDIS_URL);

const apiTool = new Tool({
  name: 'fetch_analytics',
  description: 'Fetches user analytics from the private REST API. Input: JSON with query parameters.',
  func: async (input, runManager) => {
    const response = await fetchWithRetry(input);
    return JSON.stringify(response);
  }
});

async function fetchWithRetry(input, maxRetries = 3) {
  const baseDelay = 1000;
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      const response = await fetch('/api/analytics', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: input
      });
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      return await response.json();
    } catch (err) {
      if (attempt === maxRetries - 1 || !isRetriable(err)) throw err;
      await sleep(baseDelay * Math.pow(2, attempt));
    }
  }
}

const cacheMiddleware = async (req, next) => {
  const cacheKey = `analytics:${JSON.stringify(req)}`;
  const cached = await redis.get(cacheKey);
  if (cached) return JSON.parse(cached);

  const result = await next();
  await redis.setex(cacheKey, 3600, JSON.stringify(result));
  return result;
};
```

