### 2. Hallucination Detection & Grounding Fidelity
- **Citation Match Rate**: Percentage of bot claims with valid KB anchors
- **Claim-Level Precision**: For each claim in the answer, verify it maps to a KB passage
- **Cross-Language Consistency**: Verify Spanish/Japanese KB versions contain semantically equivalent claims

### 3. Relevance Scoring
- **Intent IR Matching**: Compute cosine similarity between user query embedding and reference intent embeddings
- **Keyword Overlap**: F1 score of shared terms between query and retrieved KB passages
- **Brand Alignment**: Verify answer references correct brand context

### 4. Runnable Eval Script
```javascript
const axios = require('axios');

const EVAL_DATASET = require('./eval_dataset.json');
const KB_INDEX = require('./kb_index.json');

function extractClaims(answer) {
  return answer.split(/[.!?]/).filter(c => c.trim().length > 10);
}

function findKBCite(claim, kbDocuments) {
  const claimLower = claim.toLowerCase();
  for (const kb of kbDocuments) {
    for (const docClaim of kb.claims) {
      const similarity = computeSimilarity(claimLower, docClaim.toLowerCase());
      if (similarity > 0.7) return { kb_version: kb.version, matched: docClaim };
    }
  }
  return null;
}

function computeSimilarity(a, b) {
  const tokensA = new Set(a.split(' '));
  const tokensB = new Set(b.split(' '));
  const intersection = [...tokensA].filter(t => tokensB.has(t));
  return intersection.length / Math.max(tokensA.size, tokensB.size);
}

async function evaluateBot(prompt, botEndpoint) {
  const response = await axios.post(botEndpoint, { prompt });
  const answer = response.data.answer;

  const claims = extractClaims(answer);
  let citedClaims = 0;

  for (const claim of claims) {
    const cite = findKBCite(claim, KB_INDEX);
    if (cite) citedClaims++;
  }

  return {
    prompt_id: prompt.id,
    hallucination_rate: 1 - (citedClaims / claims.length),
    grounding_fidelity: citedClaims / claims.length,
    claim_count: claims.length
  };
}

async function runEvaluation() {
  const results = [];
  for (const prompt of EVAL_DATASET.prompts) {
    const result = await evaluateBot(prompt, 'http://localhost:3000/chat');
    results.push(result);
  }

  const avgGrounding = results.reduce((a, b) => a + b.grounding_fidelity, 0) / results.length;
  const avgHallucination = results.reduce((a, b) => a + b.hallucination_rate, 0) / results.length;

  console.log(`Grounding Fidelity: ${(avgGrounding * 100).toFixed(1)}%`);
  console.log(`Hallucination Rate: ${(avgHallucination * 100).toFixed(1)}%`);
}

runEvaluation();
```

