function extractCitations(answer, sources) {
  const sentences = answer.split(/[.!?]+/).filter(s => s.trim());
  return sentences.map(sentence => {
    const relevantSources = sources.filter(s => 
      sentence.toLowerCase().includes(s.keyphrase.toLowerCase())
    );
    return { sentence: sentence.trim(), citations: relevantSources };
  });
}

function detectConflicts(sources) {
  const conflicts = [];
  for (let i = 0; i < sources.length; i++) {
    for (let j = i + 1; j < sources.length; j++) {
      if (sources[i].contradicts?.(sources[j])) {
        conflicts.push({ sourceA: sources[i], sourceB: sources[j] });
      }
    }
  }
  return conflicts;
}

function generateAnswerWithCitations(query, policyDB, regulatoryDB) {
  const policyResults = policyDB.retrieve(query);
  const regulatoryResults = regulatoryDB.retrieve(query);
  const allSources = [...policyResults, ...regulatoryResults];

  const answer = generateAnswer(query, allSources);
  const citations = extractCitations(answer, allSources);
  const conflicts = detectConflicts(allSources);

  return { answer, citations, conflicts: conflicts.length > 0 ? conflicts : null };
}
```

