// Runnable metric: boundary-grounded pronoun accuracy (node.js)
function boundaryGroundingScore(source, summary){
  const stop = new Set(['the','a','an','and','of','in','to','for','with']);
  const isPronoun = t => /^(he|she|they|him|her|his|its|it|this|that|these|those)$/i.test(t);
  const tokenize = s => s.split(/\s+/).filter(w=>w.length);
  const sSent = source.split(/[.!?]+/).filter(x=>x.trim());
  const sumSent = summary.split(/[.!?]+/).filter(x=>x.trim());
  let grounded=0, total=0;
  // naive: consider pronouns in summary and look for uppercase word in source as antecedent
  const srcWords = tokenize(source);
  const ante = srcWords.filter(w=>/^[A-Z][a-z]+$/.test(w));
  sumSent.forEach(sent=>{
    const toks = tokenize(sent);
    toks.forEach((t,i)=>{ if(isPronoun(t)) { total++; const hasAnte = ante.length>0; if(hasAnte) grounded++; } });
  });
  return total? grounded/total: 0;
}

