// Pseudocode: local attention in blocks
function localAttention(Q, K, V, block=256, window=128){
  // Q,K,V: [B, T, D]
  const B = Q.length, T = Q[0].length, D = Q[0][0].length;
  let O = Array.from({length:B}, () => Array.from({length:T}, () => new Array(D).fill(0)));
  for (let b=0; b<B; b++){
    for (let s=0; s<T; s+=block){
      const end = Math.min(T, s+block);
      for (let t=s; t<end; t++){
        const wStart = Math.max(0, t-window);
        const wEnd = Math.min(T, t+window+1);
        // compute attention over [wStart, wEnd)
        // A = softmax((Q[t]·K[w].T)/sqrt(D))
        // O[b][t] = sum_{w=wStart}^{wEnd-1} A[w]·V[w]
      }
    }
  }
  return O;
}
```

