function buildSparseMask(n, localWin, globalAnchors) {
  const mask = Array.from({length: n}, () => Array(n).fill(false));

  // Local attention windows
  for (let i = 0; i < n; i++) {
    const start = Math.max(0, i - localWin);
    const end = Math.min(n, i + localWin + 1);
    for (let j = start; j < end; j++) {
      mask[i][j] = true;
    }
  }

  // Global anchor attention
  for (let i = 0; i < n; i++) {
    for (const anchor of globalAnchors) {
      mask[i][anchor] = true;
      mask[anchor][i] = true;
    }
  }

  return mask;
}
```

