// 1. Chunk documents into overlapping 500-token blocks
function chunkDocument(text, chunkSize = 500) {
  const tokens = text.split(' ');
  const chunks = [];
  for (let i = 0; i < tokens.length; i += chunkSize) {
    chunks.push(tokens.slice(i, i + chunkSize).join(' '));
  }
  return chunks;
}

// 2. Generate embeddings for each chunk
async function embedChunks(chunks, model) {
  return Promise.all(chunks.map(chunk => model.embed(chunk)));
}

// 3. Store embeddings in vector database
async function storeEmbeddings(embeddings, metadata) {
  await vectorDB.upsert(embeddings.map((vec, i) => ({
    id: `chunk_${i}`,
    vector: vec,
    metadata: metadata[i]
  })));
}

// 4. Retrieve top-3 by cosine similarity, then re-rank by recency
async function retrieve(query, topK = 3) {
  const queryEmbedding = await model.embed(query);
  const candidates = await vectorDB.search(queryEmbedding, topK=10);

  // Re-rank by combining relevance (cosine) and recency scores
  const ranked = candidates.map(doc => ({
    ...doc,
    score: 0.7 * doc.relevance + 0.3 * doc.recency
  })).sort((a, b) => b.score - a.score);

  return ranked.slice(0, topK);
}
```

