// Example chunking
function chunkText(text, maxChars=512){
  const words = text.split(/\\s+/);
  let chunk = '', chunks = [];
  for (const w of words){
    if ((chunk + ' ' + w).length > maxChars){
      chunks.push(chunk.trim()); chunk = w;
    } else {
      chunk += ' ' + w;
    }
  }
  if (chunk) chunks.push(chunk.trim());
  return chunks;
}
```

